// ───────────────────────────────────────────────────────────────
import { createHash } from 'node:crypto';

type JsonValue = null | boolean | number | string | JsonValue[] | { [key: string]: JsonValue };

export type DiffActionKind = 'insert' | 'upsert' | 'replace' | 'delete';

export type StatediffTargetType =
  | 'memory_index'
  | 'embedding'
  | 'embedding_cache'
  | 'fts'
  | 'bm25'
  | 'graph_edge'
  | 'causal_edge'
